const e=require("fs"),t=e.readFileSync("google_contacts_filtered.csv","utf8").split("\n"),o=[];o.push("First Name,Mobile Phone");for(let e=1;e<t.length;e++){const c=t[e].trim();if(!c)continue;const n=c.split(",");n.length>=2&&o.push(`${n[0]},${n[1]}`)}e.writeFileSync("google_contacts_fixed.csv",o.join("\n")),console.log("Fixed CSV created as google_contacts_fixed.csv");